  1â†’import { useCallback, useEffect, useMemo, useRef } from 'react';
  2â†’import { useEditor } from '@/app/EditorProvider';
  3â†’import { useProject } from '@/app/ProjectProvider';
  4â†’import { MAX_ZOOM, MIN_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  5â†’import { fitViewportToSheet } from '@/sheets/layout';
  6â†’import { hitTestViewport, hitTestViewportHandle, hitTestViewportRotationHandle } from '@/sheets/hitTest';
  7â†’import { buildSheetScene } from '@/sheets/layout';
  8â†’import styles from './SvgCanvas.module.css';
  9â†’import SheetRenderer from './SheetRenderer';
 10â†’
 11â†’function screenToSheet(screenX, screenY, viewport, svgRect) {
 12â†’  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 13â†’  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 14â†’  return { x, y };
 15â†’}
 16â†’
 17â†’export default function SheetCanvas() {
 18â†’  const svgRef = useRef(null);
 19â†’  const dragState = useRef(null);
 20â†’  const activePointerId = useRef(null);
 21â†’  const isPanning = useRef(false);
 22â†’  const lastPanPos = useRef({ x: 0, y: 0 });
 23â†’
 24â†’  const { project, dispatch } = useProject();
 25â†’  const {
 26â†’    activeSheetId,
 27â†’    selectedId,
 28â†’    selectedType,
 29â†’    viewport,
 30â†’    dispatch: editorDispatch,
 31â†’  } = useEditor();
 32â†’
 33â†’  const sheet = (project.sheets || []).find((entry) => entry.id === activeSheetId) || null;
 34â†’  const scene = useMemo(() => buildSheetScene(project, sheet), [project, sheet]);
 35â†’
 36â†’  const getSheetPos = useCallback((event) => {
 37â†’    const rect = svgRef.current.getBoundingClientRect();
 38â†’    return screenToSheet(event.clientX, event.clientY, viewport, rect);
 39â†’  }, [viewport]);
 40â†’
 41â†’  const updateViewport = useCallback((viewportId, updates) => {
 42â†’    if (!sheet) return;
 43â†’    const current = (sheet.viewports || []).find((entry) => entry.id === viewportId);
 44â†’    if (!current) return;
 45â†’    const sceneViewport = scene?.viewports.find((entry) => entry.id === viewportId) || null;
 46â†’    const isManualEdit = ['x', 'y', 'width', 'height', 'rotation'].some((key) => key in updates);
 47â†’    const baseViewport = sceneViewport
 48â†’      ? {
 49â†’          ...current,
 50â†’          x: sceneViewport.x,
 51â†’          y: sceneViewport.y,
 52â†’          width: sceneViewport.width,
 53â†’          height: sceneViewport.height,
 54â†’          rotation: sceneViewport.rotation,
 55â†’        }
 56â†’      : current;
 57â†’    const nextViewport = fitViewportToSheet({
 58â†’      ...baseViewport,
 59â†’      ...updates,
 60â†’      lockAutoLayout: 'lockAutoLayout' in updates
 61â†’        ? updates.lockAutoLayout
 62â†’        : (isManualEdit ? true : baseViewport.lockAutoLayout),
 63â†’    }, sheet);
 64â†’    dispatch({ type: 'SHEET_VIEWPORT_UPDATE', sheetId: sheet.id, viewport: nextViewport });
 65â†’  }, [dispatch, scene?.viewports, sheet]);
 66â†’
 67â†’  const capturePointer = useCallback((pointerId) => {
 68â†’    if (!svgRef.current) return;
 69â†’    activePointerId.current = pointerId;
 70â†’    try {
 71â†’      svgRef.current.setPointerCapture(pointerId);
 72â†’    } catch {
 73â†’      activePointerId.current = pointerId;
 74â†’    }
 75â†’  }, []);
 76â†’
 77â†’  const releasePointer = useCallback((pointerId = activePointerId.current) => {
 78â†’    if (!svgRef.current || pointerId == null) {
 79â†’      activePointerId.current = null;
 80â†’      return;
 81â†’    }
 82â†’    try {
 83â†’      if (svgRef.current.hasPointerCapture?.(pointerId)) {
 84â†’        svgRef.current.releasePointerCapture(pointerId);
 85â†’      }
 86â†’    } catch {
 87â†’      // Ignore browsers that reject release calls after capture is already gone.
 88â†’    }
 89â†’    activePointerId.current = null;
 90â†’  }, []);
 91â†’
 92â†’  const handlePointerDown = useCallback((event) => {
 93â†’    if (activePointerId.current !== null && activePointerId.current !== event.pointerId) return;
 94â†’
 95â†’    if (event.button === 1 || (event.button === 0 && event.shiftKey)) {
 96â†’      capturePointer(event.pointerId);
 97â†’      isPanning.current = true;
 98â†’      lastPanPos.current = { x: event.clientX, y: event.clientY };
 99â†’      event.preventDefault();
100â†’      return;
101â†’    }
102â†’
103â†’    if (event.button !== 0) return;
104â†’
105â†’    if (!sheet || !scene) return;
106â†’
107â†’    const point = getSheetPos(event);
108â†’
109â†’    if (selectedType === 'sheetViewport' && selectedId) {
110â†’      const selectedVp = scene.viewports.find((entry) => entry.id === selectedId);
111â†’      if (selectedVp && hitTestViewportRotationHandle(point, selectedVp, 6 / viewport.zoom)) {
112â†’        const cx = selectedVp.x + selectedVp.width / 2;
113â†’        const cy = selectedVp.y + selectedVp.height / 2;
114â†’        dragState.current = {
115â†’          mode: 'rotate',
116â†’          viewportId: selectedId,
117â†’          center: { x: cx, y: cy },
118â†’          initialRotation: selectedVp.rotation || 0,
119â†’          startAngle: Math.atan2(point.y - cy, point.x - cx) * (180 / Math.PI),
120â†’        };
121â†’        capturePointer(event.pointerId);
122â†’        event.preventDefault();
123â†’        return;
124â†’      }
125â†’    }
126â†’
127â†’    const handleViewportCandidates = selectedType === 'sheetViewport' && selectedId
128â†’      ? [
129â†’          ...scene.viewports.filter((entry) => entry.id === selectedId),
130â†’          ...scene.viewports.filter((entry) => entry.id !== selectedId),
131â†’        ]
132â†’      : scene.viewports;
133â†’
134â†’    const handleHit = hitTestViewportHandle(point, handleViewportCandidates, 6 / viewport.zoom);
135â†’
136â†’    if (handleHit) {
137â†’      editorDispatch({ type: 'SELECT_OBJECT', id: handleHit.viewportId, objectType: 'sheetViewport' });
138â†’      const selectedViewport = scene.viewports.find((entry) => entry.id === handleHit.viewportId);
139â†’      dragState.current = {
140â†’        mode: 'resize',
141â†’        viewportId: handleHit.viewportId,
142â†’        handle: handleHit.handle,
143â†’        origin: point,
144â†’        initialViewport: selectedViewport || sheet.viewports.find((entry) => entry.id === handleHit.viewportId),
145â†’      };
146â†’      capturePointer(event.pointerId);
147â†’      event.preventDefault();
148â†’      return;
149â†’    }
150â†’
151â†’    const viewportHit = hitTestViewport(point, scene.viewports);
152â†’    if (viewportHit) {
153â†’      editorDispatch({ type: 'SELECT_OBJECT', id: viewportHit.id, objectType: 'sheetViewport' });
154â†’      dragState.current = {
155â†’        mode: 'move',
156â†’        viewportId: viewportHit.id,
157â†’        origin: point,
158â†’        initialViewport: viewportHit,
159â†’      };
160â†’      capturePointer(event.pointerId);
161â†’      event.preventDefault();
162â†’      return;
163â†’    }
164â†’
165â†’    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
166â†’    dragState.current = null;
167â†’  }, [activePointerId, capturePointer, editorDispatch, getSheetPos, scene, selectedId, selectedType, sheet, viewport.zoom]);
168â†’
169â†’  const handlePointerMove = useCallback((event) => {
170â†’    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
171â†’
172â†’    if (isPanning.current) {
173â†’      const dx = event.clientX - lastPanPos.current.x;
174â†’      const dy = event.clientY - lastPanPos.current.y;
175â†’      editorDispatch({ type: 'PAN', dx, dy });
176â†’      lastPanPos.current = { x: event.clientX, y: event.clientY };
177â†’      return;
178â†’    }
179â†’
180â†’    if (!dragState.current || !sheet) return;
181â†’
182â†’    const point = getSheetPos(event);
183â†’    const { mode } = dragState.current;
184â†’
185â†’    if (mode === 'rotate') {
186â†’      const { center, initialRotation, startAngle, viewportId } = dragState.current;
187â†’      const currentAngle = Math.atan2(point.y - center.y, point.x - center.x) * (180 / Math.PI);
188â†’      let newRotation = initialRotation + (currentAngle - startAngle);
189â†’      if (event.shiftKey) {
190â†’        newRotation = Math.round(newRotation / 15) * 15;
191â†’      }
192â†’      newRotation = ((newRotation % 360) + 360) % 360;
193â†’      updateViewport(viewportId, { rotation: newRotation });
194â†’      return;
195â†’    }
196â†’
197â†’    const { initialViewport, origin, handle, viewportId } = dragState.current;
198â†’    const dx = point.x - origin.x;
199â†’    const dy = point.y - origin.y;
200â†’
201â†’    if (mode === 'move') {
202â†’      updateViewport(viewportId, {
203â†’        x: initialViewport.x + dx,
204â†’        y: initialViewport.y + dy,
205â†’      });
206â†’      return;
207â†’    }
208â†’
209â†’    const next = {
210â†’      x: initialViewport.x,
211â†’      y: initialViewport.y,
212â†’      width: initialViewport.width,
213â†’      height: initialViewport.height,
214â†’    };
215â†’
216â†’    if (handle.includes('n')) {
217â†’      next.y = initialViewport.y + dy;
218â†’      next.height = initialViewport.height - dy;
219â†’    }
220â†’    if (handle.includes('s')) {
221â†’      next.height = initialViewport.height + dy;
222â†’    }
223â†’    if (handle.includes('w')) {
224â†’      next.x = initialViewport.x + dx;
225â†’      next.width = initialViewport.width - dx;
226â†’    }
227â†’    if (handle.includes('e')) {
228â†’      next.width = initialViewport.width + dx;
229â†’    }
230â†’
231â†’    updateViewport(viewportId, next);
232â†’  }, [editorDispatch, getSheetPos, sheet, updateViewport]);
233â†’
234â†’  const handlePointerUp = useCallback((event) => {
235â†’    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
236â†’    isPanning.current = false;
237â†’    dragState.current = null;
238â†’    releasePointer(event.pointerId);
239â†’  }, [releasePointer]);
240â†’
241â†’  const handlePointerCancel = useCallback((event) => {
242â†’    if (activePointerId.current !== null && event.pointerId !== activePointerId.current) return;
243â†’    isPanning.current = false;
244â†’    dragState.current = null;
245â†’    releasePointer(event.pointerId);
246â†’  }, [releasePointer]);
247â†’
248â†’  const handleWheel = useCallback((event) => {
249â†’    event.preventDefault();
250â†’    const rect = svgRef.current.getBoundingClientRect();
251â†’    const mouseX = event.clientX - rect.left;
252â†’    const mouseY = event.clientY - rect.top;
253â†’    const direction = event.deltaY < 0 ? 1 : -1;
254â†’    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
255â†’    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
256â†’    const panX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
257â†’    const panY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
258â†’    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX, panY });
259â†’  }, [editorDispatch, viewport]);
260â†’
261â†’  useEffect(() => {
262â†’    const svg = svgRef.current;
263â†’    if (!svg) return undefined;
264â†’    const prevent = (event) => event.preventDefault();
265â†’    svg.addEventListener('contextmenu', prevent);
266â†’    svg.addEventListener('wheel', handleWheel, { passive: false });
267â†’    return () => {
268â†’      svg.removeEventListener('contextmenu', prevent);
269â†’      svg.removeEventListener('wheel', handleWheel);
270â†’    };
271â†’  }, [handleWheel]);
272â†’
273â†’  return (
274â†’    <div className={styles.canvasContainer}>
275â†’      <svg
276â†’        ref={svgRef}
277â†’        className={styles.svg}
278â†’        style={{ cursor: dragState.current ? 'grabbing' : 'default', touchAction: 'none' }}
279â†’        onPointerDown={handlePointerDown}
280â†’        onPointerMove={handlePointerMove}
281â†’        onPointerUp={handlePointerUp}
282â†’        onPointerCancel={handlePointerCancel}
283â†’      >
284â†’        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
285â†’          {sheet ? (
286â†’            <SheetRenderer
287â†’              project={project}
288â†’              sheet={sheet}
289â†’              selectedId={selectedId}
290â†’              selectedType={selectedType}
291â†’            />
292â†’          ) : (
293â†’            <g className="sheet-empty">
294â†’              <rect x={0} y={0} width={420} height={297} fill="#f6f7f9" stroke="#d0d6de" strokeDasharray="2 2" />
295â†’              <text x={210} y={148} textAnchor="middle" dominantBaseline="middle" fill="#66768a" fontSize={12}>
296â†’                Create a sheet from the sidebar or properties panel.
297â†’              </text>
298â†’            </g>
299â†’          )}
300â†’        </g>
301â†’      </svg>
302â†’      {sheet && scene && (
303â†’        <svg
304â†’          data-sheet-export-root="true"
305â†’          width={scene.paper.width}
306â†’          height={scene.paper.height}
307â†’          viewBox={`0 0 ${scene.paper.width} ${scene.paper.height}`}
308â†’          style={{
309â†’            position: 'absolute',
310â†’            width: 0,
311â†’            height: 0,
312â†’            overflow: 'hidden',
313â†’            pointerEvents: 'none',
314â†’            opacity: 0,
315â†’          }}
316â†’          aria-hidden="true"
317â†’        >
318â†’          <SheetRenderer
319â†’            project={project}
320â†’            sheet={sheet}
321â†’            selectedId={null}
322â†’            selectedType={null}
323â†’          />
324â†’        </svg>
325â†’      )}
326â†’      <div className={styles.statusBar}>
327â†’        <span>Workspace: sheet</span>
328â†’        <span>Sheet: {sheet?.title || 'None'}</span>
329â†’        <span>Zoom: {Math.round(viewport.zoom * 100)}%</span>
330â†’      </div>
331â†’    </div>
332â†’  );
333â†’}
334â†’

  1â†’import { buildSheetScene } from '@/sheets/layout';
  2â†’import { SHEET_COLORS } from '@/sheets/standards';
  3â†’import { getViewportHandleRects, getViewportRotationHandle } from '@/sheets/hitTest';
  4â†’import SheetViewportContent from './SheetViewportContent';
  5â†’import SheetTitleBlock from './sheet/SheetTitleBlock';
  6â†’
  7â†’const HANDLE_SIZE = 4;
  8â†’
  9â†’function EmptyViewportMessage({ viewport, message }) {
 10â†’  return (
 11â†’    <text
 12â†’      x={viewport.x + viewport.width / 2}
 13â†’      y={viewport.y + viewport.height / 2}
 14â†’      textAnchor="middle"
 15â†’      dominantBaseline="middle"
 16â†’      fill={SHEET_COLORS.textFaint}
 17â†’      fontSize={4}
 18â†’      pointerEvents="none"
 19â†’    >
 20â†’      {message}
 21â†’    </text>
 22â†’  );
 23â†’}
 24â†’
 25â†’function ViewportCaption({ viewport }) {
 26â†’  const isAbove = viewport.caption.position === 'above';
 27â†’  const ruleY = isAbove ? viewport.y - 2.2 : viewport.y + viewport.height + 1.2;
 28â†’  const secondaryY = isAbove ? viewport.y - 2.8 : viewport.caption.y;
 29â†’  const primaryY = secondaryY - 3.1;
 30â†’
 31â†’  return (
 32â†’    <g className="sheet-viewport-caption" pointerEvents="none">
 33â†’      <line
 34â†’        x1={viewport.x}
 35â†’        y1={ruleY}
 36â†’        x2={viewport.x + viewport.width}
 37â†’        y2={ruleY}
 38â†’        stroke={SHEET_COLORS.border}
 39â†’        strokeWidth={0.3}
 40â†’      />
 41â†’      <text
 42â†’        x={viewport.x}
 43â†’        y={primaryY}
 44â†’        fontSize={3}
 45â†’        fill={SHEET_COLORS.text}
 46â†’        fontWeight={600}
 47â†’        letterSpacing={0.12}
 48â†’      >
 49â†’        {viewport.caption.primaryText}
 50â†’      </text>
 51â†’      <text
 52â†’        x={viewport.x}
 53â†’        y={secondaryY}
 54â†’        fontSize={1.9}
 55â†’        fill={SHEET_COLORS.textMuted}
 56â†’        letterSpacing={0.12}
 57â†’      >
 58â†’        {viewport.caption.secondaryText}
 59â†’      </text>
 60â†’    </g>
 61â†’  );
 62â†’}
 63â†’
 64â†’export default function SheetRenderer({ project, sheet, selectedId, selectedType }) {
 65â†’  const scene = buildSheetScene(project, sheet);
 66â†’  if (!scene) return null;
 67â†’
 68â†’  return (
 69â†’    <g className="sheet">
 70â†’      <rect
 71â†’        x={0}
 72â†’        y={0}
 73â†’        width={scene.paper.width}
 74â†’        height={scene.paper.height}
 75â†’        fill={SHEET_COLORS.sheetBackdrop}
 76â†’        stroke="none"
 77â†’      />
 78â†’      <rect
 79â†’        x={scene.border.x}
 80â†’        y={scene.border.y}
 81â†’        width={scene.border.width}
 82â†’        height={scene.border.height}
 83â†’        fill={SHEET_COLORS.paper}
 84â†’        stroke={selectedType === 'sheet' && selectedId === sheet.id ? '#0f8f74' : SHEET_COLORS.border}
 85â†’        strokeWidth={selectedType === 'sheet' && selectedId === sheet.id ? 1 : 0.6}
 86â†’      />
 87â†’      <rect
 88â†’        x={scene.liveArea.x}
 89â†’        y={scene.liveArea.y}
 90â†’        width={scene.liveArea.width}
 91â†’        height={scene.liveArea.height}
 92â†’        fill="none"
 93â†’        stroke={SHEET_COLORS.divider}
 94â†’        strokeWidth={0.2}
 95â†’      />
 96â†’      <SheetTitleBlock titleBlock={scene.titleBlock} />
 97â†’
 98â†’      {scene.viewports.map((viewport) => {
 99â†’        const isSelected = selectedType === 'sheetViewport' && selectedId === viewport.id;
100â†’        return (
101â†’          <g
102â†’            key={viewport.id}
103â†’            className="sheet-viewport"
104â†’            transform={viewport.rotation ? `rotate(${viewport.rotation}, ${viewport.x + viewport.width / 2}, ${viewport.y + viewport.height / 2})` : undefined}
105â†’          >
106â†’            <ViewportCaption viewport={viewport} />
107â†’            <rect
108â†’              x={viewport.x}
109â†’              y={viewport.y}
110â†’              width={viewport.width}
111â†’              height={viewport.height}
112â†’              fill={viewport.source.kind === '3d_preview' ? '#f8fafc' : SHEET_COLORS.paper}
113â†’              stroke={isSelected ? '#0f8f74' : SHEET_COLORS.border}
114â†’              strokeWidth={isSelected ? 0.8 : 0.45}
115â†’            />
116â†’            <rect
117â†’              x={viewport.contentRect.x}
118â†’              y={viewport.contentRect.y}
119â†’              width={viewport.contentRect.width}
120â†’              height={viewport.contentRect.height}
121â†’              fill="none"
122â†’              stroke={SHEET_COLORS.divider}
123â†’              strokeWidth={0.18}
124â†’              pointerEvents="none"
125â†’            />
126â†’            {viewport.source.kind === 'empty' ? (
127â†’              <EmptyViewportMessage viewport={viewport} message={viewport.source.message} />
128â†’            ) : (
129â†’              <svg
130â†’                x={viewport.clipRect.x}
131â†’                y={viewport.clipRect.y}
132â†’                width={viewport.clipRect.width}
133â†’                height={viewport.clipRect.height}
134â†’                viewBox={`0 0 ${viewport.clipRect.width} ${viewport.clipRect.height}`}
135â†’                overflow="hidden"
136â†’                pointerEvents="none"
137â†’              >
138â†’                <g
139â†’                  transform={`translate(${viewport.contentTransform.translateX}, ${viewport.contentTransform.translateY}) scale(${viewport.contentTransform.scale})`}
140â†’                  pointerEvents="none"
141â†’                >
142â†’                  <SheetViewportContent source={viewport.source} />
143â†’                </g>
144â†’              </svg>
145â†’            )}
146â†’            {isSelected && Object.values(getViewportHandleRects(viewport, HANDLE_SIZE)).map((handleRect) => (
147â†’              <rect
148â†’                key={`${viewport.id}-${handleRect.x}-${handleRect.y}`}
149â†’                x={handleRect.x}
150â†’                y={handleRect.y}
151â†’                width={handleRect.width}
152â†’                height={handleRect.height}
153â†’                fill="#ffffff"
154â†’                stroke="#0f8f74"
155â†’                strokeWidth={0.5}
156â†’              />
157â†’            ))}
158â†’            {isSelected && (() => {
159â†’              const rh = getViewportRotationHandle(viewport, HANDLE_SIZE);
160â†’              return (
161â†’                <>
162â†’                  <line
163â†’                    x1={rh.stemX}
164â†’                    y1={rh.stemY1}
165â†’                    x2={rh.stemX}
166â†’                    y2={rh.stemY2}
167â†’                    stroke="#0f8f74"
168â†’                    strokeWidth={0.4}
169â†’                  />
170â†’                  <circle
171â†’                    cx={rh.cx}
172â†’                    cy={rh.cy}
173â†’                    r={rh.radius}
174â†’                    fill="#ffffff"
175â†’                    stroke="#0f8f74"
176â†’                    strokeWidth={0.5}
177â†’                    style={{ cursor: 'grab' }}
178â†’                  />
179â†’                </>
180â†’              );
181â†’            })()}
182â†’          </g>
183â†’        );
184â†’      })}
185â†’    </g>
186â†’  );
187â†’}
