107â†’      .catch((error) => {
108â†’        if (cancelled) return;
109â†’        console.error('Failed to render sheet 3D preview:', error);
110â†’        setPreviewState({
111â†’          status: 'error',
112â†’          imageUrl: null,
113â†’        });
