130â†’    return (
131â†’      <text
132â†’        x={centerX}
133â†’        y={centerY}
134â†’        textAnchor="middle"
135â†’        fontSize={400}
136â†’        fill="#8899aa"
137â†’        pointerEvents="none"
138â†’      >
139â†’        {messages[previewState.status] || messages.loading}
140â†’      </text>
141â†’    );
142â†’  }
143â†’
144â†’  return (
145â†’    <image
146â†’      href={previewState.imageUrl}
147â†’      x={bounds.minX}
148â†’      y={bounds.minY}
149â†’      width={bounds.maxX - bounds.minX}
150â†’      height={bounds.maxY - bounds.minY}
151â†’      preserveAspectRatio="xMidYMid meet"
152â†’      pointerEvents="none"
153â†’    />
154â†’  );
155â†’}
