10â†’export function getViewportHandleRects(viewport, handleSize) {
11â†’  const size = handleSize;
12â†’  const midX = viewport.x + viewport.width / 2;
13â†’  const midY = viewport.y + viewport.height / 2;
14â†’  return {
15â†’    nw: { x: viewport.x - size / 2, y: viewport.y - size / 2, width: size, height: size },
16â†’    n: { x: midX - size / 2, y: viewport.y - size / 2, width: size, height: size },
17â†’    ne: { x: viewport.x + viewport.width - size / 2, y: viewport.y - size / 2, width: size, height: size },
18â†’    e: { x: viewport.x + viewport.width - size / 2, y: midY - size / 2, width: size, height: size },
19â†’    se: { x: viewport.x + viewport.width - size / 2, y: viewport.y + viewport.height - size / 2, width: size, height: size },
20â†’    s: { x: midX - size / 2, y: viewport.y + viewport.height - size / 2, width: size, height: size },
21â†’    sw: { x: viewport.x - size / 2, y: viewport.y + viewport.height - size / 2, width: size, height: size },
22â†’    w: { x: viewport.x - size / 2, y: midY - size / 2, width: size, height: size },
23â†’  };
24â†’}
