26â†’export function hitTestViewportHandle(point, viewports, handleSize) {
27â†’  for (let index = viewports.length - 1; index >= 0; index -= 1) {
28â†’    const viewport = viewports[index];
29â†’    const handles = getViewportHandleRects(viewport, handleSize);
30â†’    for (const [key, rect] of Object.entries(handles)) {
31â†’      if (pointInRect(point, rect)) {
32â†’        return { viewportId: viewport.id, handle: key };
33â†’      }
34â†’    }
35â†’  }
36â†’  return null;
37â†’}
