39â†’export function getViewportRotationHandle(viewport, handleSize) {
40â†’  const cx = viewport.x + viewport.width / 2;
41â†’  const stemLength = handleSize * 2.5;
42â†’  const radius = handleSize / 2;
43â†’  const stemY1 = viewport.y;
44â†’  const stemY2 = viewport.y - stemLength;
45â†’  const cy = stemY2 - radius;
46â†’  return { cx, cy, radius, stemX: cx, stemY1, stemY2 };
47â†’}
48â†’
49â†’export function hitTestViewportRotationHandle(point, viewport, handleSize) {
50â†’  const { cx, cy, radius } = getViewportRotationHandle(viewport, handleSize);
51â†’  const dx = point.x - cx;
52â†’  const dy = point.y - cy;
53â†’  return dx * dx + dy * dy <= (radius + handleSize * 0.3) * (radius + handleSize * 0.3);
54â†’}
55â†’
56â†’export function hitTestViewport(point, viewports) {
57â†’  for (let index = viewports.length - 1; index >= 0; index -= 1) {
58â†’    const viewport = viewports[index];
59â†’    if (pointInRect(point, viewport)) {
60â†’      return viewport;
61â†’    }
62â†’  }
63â†’  return null;
64â†’}
