290â†’function layoutAutoViewports(entries, area) {
291â†’  if (!entries.length) return new Map();
292â†’
293â†’  const result = new Map();
294â†’  const roles = partitionByRole(entries);
295â†’  const primaryEntry = roles.primary[0] || roles.secondary[0] || roles.supplemental[0];
296â†’  const secondaryEntries = [
297â†’    ...roles.primary.slice(primaryEntry && roles.primary[0] === primaryEntry ? 1 : 0),
298â†’    ...roles.secondary.filter((entry) => entry !== primaryEntry),
299â†’    ...roles.supplemental.filter((entry) => entry !== primaryEntry),
300â†’  ];
301â†’
302â†’  if (!primaryEntry) return result;
303â†’
304â†’  const onlySupplemental = primaryEntry.source.kind === '3d_preview'
305â†’    && secondaryEntries.every((entry) => entry.source.kind === '3d_preview');
306â†’
307â†’  if (!secondaryEntries.length) {
308â†’    result.set(primaryEntry.viewport.id, rectFromArea(area));
309â†’    return result;
310â†’  }
311â†’
312â†’  if (onlySupplemental) {
313â†’    const areas = stackAreas(area, 1 + secondaryEntries.length);
314â†’    [primaryEntry, ...secondaryEntries].forEach((entry, index) => {
315â†’      result.set(entry.viewport.id, areas[index]);
316â†’    });
317â†’    return result;
318â†’  }
319â†’
320â†’  const primaryWidthRatio = secondaryEntries.length >= 3 ? 0.58 : 0.64;
321â†’  const primaryArea = {
322â†’    x: area.x,
323â†’    y: area.y,
324â†’    width: area.width * primaryWidthRatio - SHEET_TOKENS.viewportGutter / 2,
325â†’    height: area.height,
326â†’  };
327â†’  const sideArea = {
328â†’    x: primaryArea.x + primaryArea.width + SHEET_TOKENS.viewportGutter,
329â†’    y: area.y,
330â†’    width: area.width - primaryArea.width - SHEET_TOKENS.viewportGutter,
331â†’    height: area.height,
332â†’  };
333â†’
334â†’  result.set(primaryEntry.viewport.id, rectFromArea(primaryArea));
335â†’  stackAreas(sideArea, secondaryEntries.length).forEach((rect, index) => {
336â†’    result.set(secondaryEntries[index].viewport.id, rect);
337â†’  });
338â†’
339â†’  return result;
340â†’}
