342â†’export function buildSheetScene(project, sheet) {
343â†’  if (!sheet) return null;
344â†’
345â†’  const paper = getPaperPreset(sheet.paperSize);
346â†’  const zones = buildSheetZones(paper);
347â†’  const sourceEntries = (sheet.viewports || []).map((viewport) => ({
348â†’    viewport,
349â†’    source: resolveSheetViewportSource(project, viewport),
350â†’  }));
351â†’  const allowAutoLayout = sheet.layoutTemplate !== 'manual';
352â†’  const autoEntries = allowAutoLayout
353â†’    ? sourceEntries.filter((entry) => !entry.viewport.lockAutoLayout)
354â†’    : [];
355â†’  const manualEntries = sourceEntries.filter((entry) => entry.viewport.lockAutoLayout);
356â†’  const autoRects = layoutAutoViewports(autoEntries, zones.contentArea);
357â†’
358â†’  const sceneViewports = sourceEntries.map((entry) => {
359â†’    const rect = autoRects.get(entry.viewport.id)
360â†’      || fitViewportToSheet(entry.viewport, sheet);
361â†’    return buildViewportScene(entry.viewport, entry.source, sheet, rect);
362â†’  });
363â†’
364â†’  const sheetIndex = (project?.sheets || []).findIndex((entry) => entry.id === sheet.id);
365â†’
366â†’  return {
367â†’    paper,
368â†’    title: getSheetDisplayLabel(sheet, Math.max(0, sheetIndex)),
369â†’    border: zones.border,
370â†’    liveArea: zones.liveArea,
371â†’    contentArea: zones.contentArea,
372â†’    footer: zones.footer,
373â†’    titleBlock: buildTitleBlock(project, sheet, zones.titleBlock, Math.max(0, sheetIndex), sceneViewports),
374â†’    viewports: sceneViewports,
375â†’    graphics: {
376â†’      colors: SHEET_COLORS,
377â†’      drawing: DRAWING_GRAPHICS,
378â†’    },
379â†’    manualViewportCount: manualEntries.length,
380â†’  };
381â†’}
