383â†’export function materializeSheetViewportFrames(project, sheet) {
384â†’  if (!sheet) return sheet;
385â†’
386â†’  const scene = buildSheetScene(project, {
387â†’    ...sheet,
388â†’    layoutTemplate: 'auto',
389â†’  });
390â†’
391â†’  if (!scene) return sheet;
392â†’
393â†’  const frameById = new Map(scene.viewports.map((viewport) => [viewport.id, viewport]));
394â†’
395â†’  return {
396â†’    ...sheet,
