 18â†’function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 19â†’  if (!points.length) return fallback;
 20â†’  return {
 21â†’    minX: Math.min(...points.map((point) => point.x)),
 22â†’    maxX: Math.max(...points.map((point) => point.x)),
 23â†’    minY: Math.min(...points.map((point) => point.y)),
 24â†’    maxY: Math.max(...points.map((point) => point.y)),
 25â†’  };
 26â†’}
 27â†’
 28â†’function expandBounds(bounds, paddingX, paddingY = paddingX) {
 29â†’  return {
 30â†’    minX: bounds.minX - paddingX,
 31â†’    maxX: bounds.maxX + paddingX,
 32â†’    minY: bounds.minY - paddingY,
 33â†’    maxY: bounds.maxY + paddingY,
 34â†’  };
 35â†’}
