 37â†’function collectPlanPoints(floor) {
 38â†’  const points = [];
 39â†’
 40â†’  for (const wall of floor.walls || []) {
 41â†’    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
 42â†’  }
 43â†’  for (const room of floor.rooms || []) {
 44â†’    points.push(...(room.points || []));
 45â†’  }
 46â†’  for (const beam of floor.beams || []) {
 47â†’    const renderData = getBeamRenderData(beam, floor.columns || []);
 48â†’    if (renderData?.outline) points.push(...renderData.outline);
 49â†’  }
 50â†’  for (const stair of floor.stairs || []) {
 51â†’    const renderData = getStairRenderData(stair);
 52â†’    if (renderData?.outline) points.push(...renderData.outline);
 53â†’  }
 54â†’  for (const landing of floor.landings || []) {
 55â†’    points.push(...landingOutline(landing));
 56â†’  }
 57â†’  for (const column of floor.columns || []) {
 58â†’    points.push(...columnOutline(column));
 59â†’  }
 60â†’  for (const slab of (floor.slabs || [])) {
 61â†’    const rd = getSlabRenderData(slab);
 62â†’    if (rd?.boundaryPoints) points.push(...rd.boundaryPoints);
 63â†’  }
 64â†’  for (const sc of (floor.sectionCuts || [])) {
 65â†’    points.push(sc.startPoint, sc.endPoint);
 66â†’    const renderData = getSectionCutRenderData(sc);
 67â†’    if (renderData?.arrow) {
 68â†’      points.push(renderData.arrow.shaftStart, renderData.arrow.shaftEnd, renderData.arrow.headA, renderData.arrow.headB);
 69â†’    }
 70â†’  }
 71â†’
 72â†’  for (const door of floor.doors || []) {
 73â†’    const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
 74â†’    if (!wall) continue;
 75â†’    const outline = doorOutlineOnWall(wall, door);
 76â†’    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 77â†’  }
 78â†’
 79â†’  for (const windowItem of floor.windows || []) {
 80â†’    const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
 81â†’    if (!wall) continue;
 82â†’    const outline = windowOutlineOnWall(wall, windowItem);
 83â†’    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 84â†’  }
 85â†’
 86â†’  return points;
 87â†’}
