 20â†’function clearSelectionState(state) {
 21â†’  return {
 22â†’    ...state,
 23â†’    selectedId: null,
 24â†’    selectedType: null,
 25â†’    regionSelection: null,
 26â†’    pastePreview: { active: false, point: null },
 27â†’  };
