 30â†’function editorReducer(state, action) {
 31â†’  switch (action.type) {
 32â†’    case 'SET_TOOL':
 33â†’      return {
 34â†’        ...clearSelectionState(state),
 35â†’        activeTool: action.tool,
 36â†’        toolState: {},
 37â†’        statusMessage: null,
 38â†’      };
 39â†’
 40â†’    case 'SET_VIEW_MODE':
 41â†’      return {
 42â†’        ...clearSelectionState(state),
 43â†’        workspaceMode: 'model',
 44â†’        viewMode: normalizeViewMode(action.viewMode),
 45â†’        activeSectionCutId: action.sectionCutId ?? state.activeSectionCutId,
 46â†’        viewport: { ...state.modelViewport },
 47â†’        toolState: {},
 48â†’        statusMessage: null,
 49â†’      };
 50â†’
 51â†’    case 'SET_WORKSPACE_MODE':
 52â†’      return {
 53â†’        ...clearSelectionState(state),
 54â†’        workspaceMode: action.workspaceMode,
 55â†’        viewport: action.workspaceMode === 'sheet'
 56â†’          ? { ...state.sheetViewport }
 57â†’          : { ...state.modelViewport },
 58â†’        toolState: {},
 59â†’        statusMessage: null,
 60â†’      };
 61â†’
 62â†’    case 'SET_ACTIVE_SHEET':
 63â†’      return {
 64â†’        ...clearSelectionState(state),
 65â†’        activeSheetId: action.sheetId,
 66â†’        statusMessage: null,
 67â†’      };
 68â†’
 69â†’    case 'SELECT_OBJECT':
 70â†’      return {
 71â†’        ...clearSelectionState(state),
 72â†’        selectedId: action.id,
 73â†’        selectedType: action.objectType,
 74â†’      };
 75â†’
 76â†’    case 'DESELECT':
 77â†’      return clearSelectionState(state);
 78â†’
 79â†’    case 'SET_REGION_SELECTION':
 80â†’      return {
 81â†’        ...clearSelectionState(state),
 82â†’        regionSelection: action.selection && action.bounds
 83â†’          ? {
 84â†’              bounds: action.bounds,
 85â†’              selection: action.selection,
 86â†’              objectCount: Object.values(action.selection).reduce((count, ids) => count + (ids?.length || 0), 0),
 87â†’            }
 88â†’          : null,
 89â†’      };
 90â†’
 91â†’    case 'UPDATE_TOOL_STATE':
 92â†’      return {
 93â†’        ...state,
 94â†’        toolState: { ...state.toolState, ...action.payload },
 95â†’      };
 96â†’
 97â†’    case 'SET_VIEWPORT':
 98â†’      return {
 99â†’        ...state,
100â†’        modelViewport: state.workspaceMode === 'model' ? { ...action.viewport } : state.modelViewport,
101â†’        sheetViewport: state.workspaceMode === 'sheet' ? { ...action.viewport } : state.sheetViewport,
102â†’        viewport: { ...action.viewport },
103â†’      };
104â†’
105â†’    case 'PAN':
106â†’      return {
107â†’        ...state,
108â†’        modelViewport: state.workspaceMode === 'model'
109â†’          ? {
110â†’              ...state.modelViewport,
111â†’              panX: state.modelViewport.panX + action.dx,
112â†’              panY: state.modelViewport.panY + action.dy,
113â†’            }
114â†’          : state.modelViewport,
115â†’        sheetViewport: state.workspaceMode === 'sheet'
116â†’          ? {
117â†’              ...state.sheetViewport,
118â†’              panX: state.sheetViewport.panX + action.dx,
119â†’              panY: state.sheetViewport.panY + action.dy,
120â†’            }
121â†’          : state.sheetViewport,
122â†’        viewport: {
123â†’          ...state.viewport,
124â†’          panX: state.viewport.panX + action.dx,
125â†’          panY: state.viewport.panY + action.dy,
126â†’        },
127â†’      };
128â†’
129â†’    case 'ZOOM': {
130â†’      const { zoom, panX, panY } = action;
131â†’      return {
132â†’        ...state,
133â†’        modelViewport: state.workspaceMode === 'model' ? { zoom, panX, panY } : state.modelViewport,
134â†’        sheetViewport: state.workspaceMode === 'sheet' ? { zoom, panX, panY } : state.sheetViewport,
135â†’        viewport: { zoom, panX, panY },
136â†’      };
137â†’    }
138â†’
139â†’    case 'TOGGLE_GRID':
140â†’      return { ...state, showGrid: !state.showGrid };
141â†’
142â†’    case 'TOGGLE_SNAP':
143â†’      return { ...state, snapEnabled: !state.snapEnabled };
144â†’
145â†’    case 'SET_ACTIVE_FLOOR':
146â†’      return {
147â†’        ...clearSelectionState(state),
148â†’        activeFloorId: action.floorId,
149â†’        toolState: {},
150â†’        statusMessage: null,
151â†’      };
152â†’
153â†’    case 'SET_STATUS_MESSAGE':
154â†’      return { ...state, statusMessage: action.message };
155â†’
156â†’    case 'CLEAR_STATUS_MESSAGE':
157â†’      if (!state.statusMessage) return state;
158â†’      return { ...state, statusMessage: null };
159â†’
160â†’    case 'START_PASTE_PREVIEW':
161â†’      return {
162â†’        ...state,
163â†’        selectedId: null,
164â†’        selectedType: null,
165â†’        regionSelection: null,
166â†’        pastePreview: {
167â†’          active: true,
168â†’          point: action.point ?? null,
169â†’        },
170â†’      };
171â†’
172â†’    case 'UPDATE_PASTE_PREVIEW':
173â†’      if (!state.pastePreview?.active) return state;
174â†’      return {
175â†’        ...state,
176â†’        pastePreview: {
177â†’          active: true,
178â†’          point: action.point,
179â†’        },
180â†’      };
181â†’
182â†’    case 'CANCEL_PASTE_PREVIEW':
183â†’      if (!state.pastePreview?.active) return state;
184â†’      return {
185â†’        ...state,
186â†’        pastePreview: {
187â†’          active: false,
188â†’          point: null,
189â†’        },
190â†’      };
191â†’
192â†’    case 'TOGGLE_MAXIMIZE_PANEL':
193â†’      return {
194â†’        ...state,
195â†’        maximizedPanel: state.maximizedPanel === action.panel ? null : action.panel,
196â†’      };
197â†’
198â†’    default:
199â†’      return state;
200â†’  }
201â†’}
