228â†’export function EditorProvider({ children, initialActiveFloorId = null, availableFloorIds = [] }) {
229â†’  const [state, dispatch] = useReducer(
230â†’    editorReducer,
231â†’    initialActiveFloorId,
232â†’    createInitialEditorState
233â†’  );
234â†’
235â†’  useEffect(() => {
236â†’    if (!availableFloorIds.length) {
237â†’      if (state.activeFloorId !== null) {
238â†’        dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: null });
239â†’      }
240â†’      return;
241â†’    }
242â†’
243â†’    if (!state.activeFloorId || !availableFloorIds.includes(state.activeFloorId)) {
244â†’      dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: availableFloorIds[0] });
245â†’    }
246â†’  }, [availableFloorIds, state.activeFloorId]);
247â†’
248â†’  return (
249â†’    <EditorContext.Provider value={{ state, dispatch }}>
250â†’      {children}
251â†’    </EditorContext.Provider>
252â†’  );
253â†’}
