255â†’export function useEditor() {
256â†’  const ctx = useContext(EditorContext);
257â†’  if (!ctx) throw new Error('useEditor must be used within EditorProvider');
258â†’  return { ...ctx.state, dispatch: ctx.dispatch };
259â†’}
