 49â†’export function nextSectionLabel(existingCuts = []) {
 50â†’  const usedLetters = new Set(
 51â†’    existingCuts
 52â†’      .map(c => {
 53â†’        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 54â†’        return match ? match[1] : null;
 55â†’      })
 56â†’      .filter(Boolean)
 57â†’  );
 58â†’  for (let i = 0; i < 26; i++) {
 59â†’    const letter = String.fromCharCode(65 + i);
 60â†’    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 61â†’  }
 62â†’  return `Section ${existingCuts.length + 1}`;
 63â†’}
