569â†’    case 'REDO': {
570â†’      if (state.future.length === 0) return state;
571â†’      const nextProject = state.future[0];
572â†’      return {
573â†’        ...state,
574â†’        project: nextProject,
575â†’        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
576â†’        future: state.future.slice(1),
577â†’        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
578â†’      };
579â†’    }
580â†’
581â†’    default:
582â†’      return state;
583â†’  }
584â†’}
