597â†’export function ProjectProvider({ children }) {
598â†’  const [state, dispatch] = useReducer(projectReducer, initialState);
599â†’  return (
600â†’    <ProjectContext.Provider value={{ state, dispatch }}>
601â†’      {children}
602â†’    </ProjectContext.Provider>
603â†’  );
