606â†’export function useProject() {
607â†’  const ctx = useContext(ProjectContext);
608â†’  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
609â†’  const { state, dispatch } = ctx;
610â†’
611â†’  const duplicateFloor = (floorId) => {
612â†’    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
613â†’    return floor ? createDuplicatedFloor(floor) : null;
614â†’  };
615â†’
616â†’  return {
617â†’    project: state.project,
618â†’    isDirty: state.isDirty,
619â†’    lastSavedAt: state.lastSavedAt,
620â†’    canUndo: state.history.length > 0,
621â†’    canRedo: state.future.length > 0,
622â†’    dispatch,
623â†’    duplicateFloor,
624â†’    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
625â†’  };
626â†’}
