 1â†’function pointInRect(point, rect) {
 2â†’  return (
 3â†’    point.x >= rect.x
 4â†’    && point.x <= rect.x + rect.width
 5â†’    && point.y >= rect.y
 6â†’    && point.y <= rect.y + rect.height
 7â†’  );
 8â†’}
