 17â†’function hitTest(modelPos, floor, annotationTolerance) {
 18â†’  // Hit test doors first (smaller targets, higher priority)
 19â†’  for (const door of floor.doors) {
 20â†’    const wall = floor.walls.find(w => w.id === door.wallId);
 21â†’    if (!wall) continue;
 22â†’    const info = doorOutlineOnWall(wall, door);
 23â†’    const poly = [info.p1, info.p2, info.p3, info.p4];
 24â†’    if (pointInPolygon(modelPos, poly)) {
 25â†’      return { id: door.id, type: 'door' };
 26â†’    }
 27â†’  }
 28â†’
 29â†’  // Hit test windows
 30â†’  for (const win of floor.windows) {
 31â†’    const wall = floor.walls.find(w => w.id === win.wallId);
 32â†’    if (!wall) continue;
 33â†’    const info = windowOutlineOnWall(wall, win);
 34â†’    const poly = [info.p1, info.p2, info.p3, info.p4];
 35â†’    if (pointInPolygon(modelPos, poly)) {
 36â†’      return { id: win.id, type: 'window' };
 37â†’    }
 38â†’  }
 39â†’
 40â†’  // Hit test walls
 41â†’  // Hit test columns
 42â†’  for (const sc of (floor.sectionCuts || [])) {
 43â†’    if (hitTestSectionCut(modelPos, sc, annotationTolerance)) {
 44â†’      return { id: sc.id, type: 'sectionCut' };
 45â†’    }
 46â†’  }
 47â†’
 48â†’  for (const column of (floor.columns || [])) {
 49â†’    const outline = columnOutline(column);
 50â†’    if (pointInPolygon(modelPos, outline)) {
 51â†’      return { id: column.id, type: 'column' };
 52â†’    }
 53â†’  }
 54â†’
 55â†’  // Hit test fixtures
 56â†’  for (const fixture of (floor.fixtures || [])) {
 57â†’    if (fixtureContainsPoint(fixture, modelPos)) {
 58â†’      return { id: fixture.id, type: 'fixture' };
 59â†’    }
 60â†’  }
 61â†’
 62â†’  // Hit test beams
 63â†’  for (const beam of (floor.beams || [])) {
 64â†’    const renderData = getBeamRenderData(beam, floor.columns || []);
 65â†’    if (!renderData) continue;
 66â†’    if (pointInPolygon(modelPos, renderData.outline)) {
 67â†’      return { id: beam.id, type: 'beam' };
 68â†’    }
 69â†’  }
 70â†’
 71â†’  // Hit test walls
 72â†’  for (const wall of floor.walls) {
 73â†’    const outline = getWallRenderData(wall, floor.columns || []).outline;
 74â†’    if (pointInPolygon(modelPos, outline)) {
 75â†’      return { id: wall.id, type: 'wall' };
 76â†’    }
 77â†’  }
 78â†’
 79â†’  // Hit test stairs after walls/beams/columns so current editing priority stays intact.
 80â†’  for (const stair of (floor.stairs || [])) {
 81â†’    const renderData = getStairRenderData(stair);
 82â†’    if (!renderData) continue;
 83â†’    if (pointInPolygon(modelPos, renderData.outline)) {
 84â†’      return { id: stair.id, type: 'stair' };
 85â†’    }
 86â†’  }
 87â†’
 88â†’  // Hit test landings
 89â†’  for (const landing of (floor.landings || [])) {
 90â†’    if (landingContainsPoint(landing, modelPos)) {
 91â†’      return { id: landing.id, type: 'landing' };
 92â†’    }
 93â†’  }
 94â†’
 95â†’  // Hit test rooms (lowest priority)
 96â†’  for (const room of floor.rooms) {
 97â†’    if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
 98â†’      return { id: room.id, type: 'room' };
 99â†’    }
100â†’  }
101â†’
102â†’  for (const slab of (floor.slabs || [])) {
103â†’    if (slabContainsPoint(slab, modelPos)) {
104â†’      return { id: slab.id, type: 'slab' };
105â†’    }
106â†’  }
107â†’
108â†’  const annotationHit = hitTestAnnotation(modelPos, floor, annotationTolerance);
109â†’  if (annotationHit) {
110â†’    return annotationHit;
111â†’  }
112â†’
113â†’  return null;
114â†’}
