116â†’export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
117â†’  return {
118â†’    onMouseDown(modelPos, e, toolState) {
119â†’      if (e.button !== 0) return;
120â†’
121â†’      const floor = getFloor(activeFloorId);
122â†’      if (!floor) return;
123â†’
124â†’      // Check if clicking a handle
125â†’      const target = e.target;
126â†’      if (target.dataset.handle) {
127â†’        editorDispatch({
128â†’          type: 'UPDATE_TOOL_STATE',
129â†’          payload: {
130â†’            dragging: true,
131â†’            dragType: 'handle',
132â†’            handle: target.dataset.handle,
133â†’            handleIndex: target.dataset.index != null ? Number(target.dataset.index) : null,
134â†’            startPos: modelPos,
135â†’          },
136â†’        });
137â†’        return;
138â†’      }
139â†’
140â†’      const hit = hitTest(modelPos, floor, SNAP_DISTANCE_PX / viewport.zoom * 2.5);
141â†’      if (hit) {
142â†’        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
143â†’        const draggableTypes = new Set(['wall', 'column', 'fixture', 'door', 'window', 'stair', 'sectionCut', 'landing']);
144â†’        if (!draggableTypes.has(hit.type)) return;
145â†’        editorDispatch({
146â†’          type: 'UPDATE_TOOL_STATE',
147â†’          payload: {
148â†’            dragging: true,
149â†’            dragType: 'move',
150â†’            startPos: modelPos,
151â†’            originalPos: modelPos,
152â†’          },
153â†’        });
154â†’      } else {
155â†’        editorDispatch({
156â†’          type: 'UPDATE_TOOL_STATE',
157â†’          payload: {
158â†’            dragging: true,
159â†’            dragType: 'marquee',
160â†’            startPos: modelPos,
161â†’            currentPos: modelPos,
162â†’          },
163â†’        });
164â†’      }
165â†’    },
166â†’
167â†’    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
168â†’      if (toolState.dragging && toolState.dragType === 'marquee') {
169â†’        editorDispatch({
170â†’          type: 'UPDATE_TOOL_STATE',
171â†’          payload: { currentPos: modelPos },
172â†’        });
173â†’        return;
174â†’      }
175â†’
176â†’      if (!toolState.dragging || !selectedId) return;
177â†’
178â†’      const floor = getFloor(activeFloorId);
179â†’      if (!floor) return;
180â†’      const dx = modelPos.x - toolState.startPos.x;
181â†’      const dy = modelPos.y - toolState.startPos.y;
182â†’      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
183â†’
184â†’      if (selectedType === 'wall') {
185â†’        const wall = floor.walls.find(w => w.id === selectedId);
186â†’        if (!wall) return;
187â†’        const resolved = resolveWallEndpoints(wall, floor.columns || []);
188â†’
189â†’        if (toolState.dragType === 'handle') {
190â†’          const handle = toolState.handle;
191â†’          const oppositeKey = handle === 'start' ? 'end' : 'start';
192â†’          const oppositePoint = resolved[oppositeKey];
193â†’          let nextPoint = modelPos;
194â†’          let nextAttachment = null;
195â†’
196â†’          if (e.shiftKey) {
197â†’            const dx = modelPos.x - oppositePoint.x;
198â†’            const dy = modelPos.y - oppositePoint.y;
199â†’            const angle = Math.atan2(dy, dx);
200â†’            const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
201â†’            const len = Math.sqrt(dx * dx + dy * dy);
202â†’            nextPoint = {
203â†’              x: oppositePoint.x + Math.cos(snapAngle) * len,
204â†’              y: oppositePoint.y + Math.sin(snapAngle) * len,
205â†’            };
206â†’          } else if (snapEnabled) {
207â†’            const snapResult = snapWallEndpoint(modelPos, {
208â†’              walls: floor.walls,
209â†’              columns: floor.columns || [],
210â†’              snapDist: snapDistModel,
211â†’              otherPoint: oppositePoint,
212â†’              ignoreWallId: wall.id,
213â†’            });
214â†’            if (snapResult) {
215â†’              nextPoint = snapResult.point;
216â†’              nextAttachment = snapResult.attachment;
217â†’            }
218â†’          }
219â†’
220â†’          if (distance(nextPoint, oppositePoint) < MIN_WALL_LENGTH) return;
221â†’
222â†’          dispatch({
223â†’            type: 'WALL_UPDATE',
224â†’            floorId: activeFloorId,
225â†’            wall: {
226â†’              id: wall.id,
227â†’              [handle]: nextPoint,
228â†’              [`${handle}Attachment`]: nextAttachment,
229â†’            },
230â†’          });
231â†’        } else {
232â†’          let nextStart = { x: resolved.start.x + dx, y: resolved.start.y + dy };
233â†’          let nextEnd = { x: resolved.end.x + dx, y: resolved.end.y + dy };
234â†’          let startAttachment = null;
235â†’          let endAttachment = null;
236â†’
237â†’          if (snapEnabled) {
238â†’            const startSnap = snapWallEndpoint(nextStart, {
239â†’              walls: floor.walls,
240â†’              columns: floor.columns || [],
241â†’              snapDist: snapDistModel,
242â†’              otherPoint: nextEnd,
243â†’              ignoreWallId: wall.id,
244â†’            });
245â†’            if (startSnap) {
246â†’              nextStart = startSnap.point;
247â†’              startAttachment = startSnap.attachment;
248â†’            }
249â†’
250â†’            const endSnap = snapWallEndpoint(nextEnd, {
251â†’              walls: floor.walls,
252â†’              columns: floor.columns || [],
253â†’              snapDist: snapDistModel,
254â†’              otherPoint: nextStart,
255â†’              ignoreWallId: wall.id,
256â†’            });
257â†’            if (endSnap) {
258â†’              nextEnd = endSnap.point;
259â†’              endAttachment = endSnap.attachment;
260â†’            }
261â†’          }
262â†’
263â†’          if (distance(nextStart, nextEnd) < MIN_WALL_LENGTH) return;
264â†’
265â†’          dispatch({
266â†’            type: 'WALL_UPDATE',
267â†’            floorId: activeFloorId,
268â†’            wall: {
269â†’              id: wall.id,
270â†’              start: nextStart,
271â†’              end: nextEnd,
272â†’              startAttachment,
273â†’              endAttachment,
274â†’            },
275â†’          });
276â†’        }
277â†’        editorDispatch({
278â†’          type: 'UPDATE_TOOL_STATE',
279â†’          payload: { startPos: modelPos },
280â†’        });
281â†’      } else if (selectedType === 'column') {
282â†’        const col = (floor.columns || []).find(c => c.id === selectedId);
283â†’        if (!col) return;
284â†’        dispatch({
285â†’          type: 'COLUMN_UPDATE',
286â†’          floorId: activeFloorId,
287â†’          column: { id: col.id, x: col.x + dx, y: col.y + dy },
288â†’        });
289â†’        editorDispatch({
290â†’          type: 'UPDATE_TOOL_STATE',
291â†’          payload: { startPos: modelPos },
292â†’        });
293â†’      } else if (selectedType === 'fixture') {
294â†’        const fixture = (floor.fixtures || []).find(f => f.id === selectedId);
295â†’        if (!fixture) return;
296â†’        dispatch({
297â†’          type: 'FIXTURE_UPDATE',
298â†’          floorId: activeFloorId,
299â†’          fixture: { id: fixture.id, x: fixture.x + dx, y: fixture.y + dy },
300â†’        });
301â†’        editorDispatch({
302â†’          type: 'UPDATE_TOOL_STATE',
303â†’          payload: { startPos: modelPos },
304â†’        });
305â†’      } else if (selectedType === 'sectionCut') {
306â†’        const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId);
307â†’        if (!sectionCut) return;
308â†’
309â†’        if (toolState.dragType === 'handle') {
310â†’          const handle = toolState.handle;
311â†’          const nextSectionCut = handle === 'start'
312â†’            ? { ...sectionCut, startPoint: modelPos }
313â†’            : { ...sectionCut, endPoint: modelPos };
314â†’
315â†’          if (distance(nextSectionCut.startPoint, nextSectionCut.endPoint) < MIN_WALL_LENGTH) return;
316â†’
317â†’          dispatch({
