341â†’          });
342â†’        }
343â†’      } else if (selectedType === 'beam') {
344â†’        return;
345â†’      } else if (selectedType === 'stair') {
346â†’        const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
347â†’        if (!stair) return;
348â†’        dispatch({
349â†’          type: 'STAIR_UPDATE',
350â†’          floorId: activeFloorId,
351â†’          stair: {
352â†’            id: stair.id,
353â†’            startPoint: {
354â†’              x: stair.startPoint.x + dx,
355â†’              y: stair.startPoint.y + dy,
356â†’            },
357â†’          },
358â†’        });
359â†’        editorDispatch({
360â†’          type: 'UPDATE_TOOL_STATE',
361â†’          payload: { startPos: modelPos },
362â†’        });
363â†’      } else if (selectedType === 'landing') {
364â†’        const landing = (floor.landings || []).find(l => l.id === selectedId);
365â†’        if (!landing) return;
366â†’        dispatch({
367â†’          type: 'LANDING_UPDATE',
368â†’          floorId: activeFloorId,
369â†’          landing: {
