484â†’    onKeyDown(e, toolState, selectedId, selectedType) {
485â†’      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'd' && selectedId && selectedType === 'column') {
486â†’        e.preventDefault();
487â†’        const floor = getFloor(activeFloorId);
