504â†’        } else if (selectedType === 'window') {
505â†’          dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
506â†’        } else if (selectedType === 'column') {
507â†’          dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
508â†’        } else if (selectedType === 'fixture') {
509â†’          dispatch({ type: 'FIXTURE_DELETE', floorId: activeFloorId, fixtureId: selectedId });
510â†’        } else if (selectedType === 'beam') {
511â†’          dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
512â†’        } else if (selectedType === 'stair') {
513â†’          dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
514â†’        } else if (selectedType === 'landing') {
515â†’          dispatch({ type: 'LANDING_DELETE', floorId: activeFloorId, landingId: selectedId });
516â†’        } else if (selectedType === 'annotation') {
517â†’          dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
518â†’        } else if (selectedType === 'slab') {
