47â†’      } else if (e.key === 'Escape') {
48â†’        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
49â†’      }
50â†’    },
51â†’
52â†’    getCursor() {
53â†’      return 'crosshair';
54â†’    },
55â†’  };
