100â†’export function formatSheetDate(value) {
101â†’  if (!value) return '';
102â†’  const date = new Date(value);
103â†’  if (Number.isNaN(date.getTime())) return String(value);
104â†’  const year = date.getFullYear();
105â†’  const month = String(date.getMonth() + 1).padStart(2, '0');
106â†’  const day = String(date.getDate()).padStart(2, '0');
107â†’  return `${year}-${month}-${day}`;
108â†’}
