120â†’export function resolveViewportScaleLabel(viewport, source, sheet) {
121â†’  if (source?.kind === '3d_preview') return 'NTS';
122â†’  if (sheet?.scaleMode === 'as_noted') return 'As noted';
123â†’  return `1:${Math.max(1, Math.round(Number(viewport?.scale) || 100))}`;
