126â†’export function resolveViewportReferenceNote(viewport, source) {
127â†’  const custom = viewport?.referenceNote?.trim();
128â†’  if (custom) return custom;
129â†’  if (source?.kind === '3d_preview') return 'AXONOMETRIC VIEW';
130â†’  if (source?.kind === 'section') return 'BUILDING SECTION';
131â†’  if (source?.kind === 'elevation') return 'EXTERIOR ELEVATION';
