135â†’export function resolveSheetScaleLabel(sheet, viewports = []) {
136â†’  if (sheet?.scaleMode === 'as_noted') return 'As noted';
137â†’  if (sheet?.scaleMode === 'per_viewport') return 'As noted';
138â†’
139â†’  const explicit = sheet?.scaleLabel?.trim();
140â†’  if (explicit) return explicit;
141â†’
142â†’  const scales = [...new Set(viewports
143â†’    .filter((viewport) => viewport.source?.kind !== '3d_preview')
144â†’    .map((viewport) => Math.max(1, Math.round(Number(viewport.scale) || 100))) )];
145â†’
146â†’  if (scales.length === 1) return `1:${scales[0]}`;
147â†’  return 'As noted';
148â†’}
