261â†’function stackAreas(area, count) {
262â†’  if (count <= 0) return [];
263â†’  if (count === 1) return [rectFromArea(area)];
264â†’  if (count >= 4) {
265â†’    const columns = 2;
266â†’    const rows = Math.ceil(count / columns);
267â†’    const cellWidth = (area.width - SHEET_TOKENS.viewportGutter) / columns;
268â†’    const cellHeight = (area.height - SHEET_TOKENS.viewportGutter * (rows - 1)) / rows;
269â†’    return Array.from({ length: count }, (_, index) => {
270â†’      const column = index % columns;
271â†’      const row = Math.floor(index / columns);
272â†’      return {
273â†’        x: area.x + column * (cellWidth + SHEET_TOKENS.viewportGutter),
274â†’        y: area.y + row * (cellHeight + SHEET_TOKENS.viewportGutter),
275â†’        width: cellWidth,
276â†’        height: cellHeight,
277â†’      };
278â†’    });
279â†’  }
280â†’
281â†’  const height = (area.height - SHEET_TOKENS.viewportGutter * (count - 1)) / count;
282â†’  return Array.from({ length: count }, (_, index) => ({
283â†’    x: area.x,
284â†’    y: area.y + index * (height + SHEET_TOKENS.viewportGutter),
285â†’    width: area.width,
286â†’    height,
287â†’  }));
288â†’}
