330â†’    width: area.width - primaryArea.width - SHEET_TOKENS.viewportGutter,
331â†’    height: area.height,
332â†’  };
333â†’
334â†’  result.set(primaryEntry.viewport.id, rectFromArea(primaryArea));
335â†’  stackAreas(sideArea, secondaryEntries.length).forEach((rect, index) => {
336â†’    result.set(secondaryEntries[index].viewport.id, rect);
337â†’  });
338â†’
339â†’  return result;
340â†’}
