389â†’  });
390â†’
391â†’  if (!scene) return sheet;
392â†’
393â†’  const frameById = new Map(scene.viewports.map((viewport) => [viewport.id, viewport]));
394â†’
395â†’  return {
396â†’    ...sheet,
397â†’    layoutTemplate: 'manual',
398â†’    viewports: (sheet.viewports || []).map((viewport) => {
399â†’      const frame = frameById.get(viewport.id);
