404â†’        };
405â†’      }
406â†’
407â†’      return {
408â†’        ...viewport,
409â†’        x: frame.x,
410â†’        y: frame.y,
411â†’        width: frame.width,
412â†’        height: frame.height,
413â†’        rotation: frame.rotation || 0,
414â†’        lockAutoLayout: true,
415â†’      };
416â†’    }),
417â†’  };
418â†’}
