449â†’export function getDefaultViewportRect(sheet, source, scale = 100, options = {}) {
450â†’  const paper = getPaperPreset(sheet.paperSize);
451â†’  const zones = buildSheetZones(paper);
452â†’  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
453â†’  const sourceWidth = Math.max(1000, bounds.maxX - bounds.minX);
454â†’  const sourceHeight = Math.max(1000, bounds.maxY - bounds.minY);
455â†’  const role = options.role || (source.kind === '3d_preview' ? 'supplemental' : 'primary');
456â†’  const baseScale = source.kind === '3d_preview' ? 1 : Math.max(1, scale);
457â†’  const width = clamp(
458â†’    source.kind === '3d_preview'
459â†’      ? zones.contentArea.width * 0.72
460â†’      : (sourceWidth / baseScale) + SHEET_TOKENS.viewportPadding * 2,
461â†’    role === 'primary' ? 120 : 84,
462â†’    role === 'primary' ? zones.contentArea.width * 0.72 : zones.contentArea.width * 0.44
463â†’  );
464â†’  const height = clamp(
465â†’    source.kind === '3d_preview'
466â†’      ? zones.contentArea.height * 0.54
467â†’      : (sourceHeight / baseScale) + SHEET_TOKENS.viewportPadding * 2,
468â†’    role === 'primary' ? 96 : 72,
469â†’    role === 'primary' ? zones.contentArea.height * 0.78 : zones.contentArea.height * 0.42
470â†’  );
471â†’
472â†’  return snapRectToGrid({
473â†’    x: zones.contentArea.x + SHEET_TOKENS.viewportGutter,
474â†’    y: zones.contentArea.y + SHEET_TOKENS.viewportGutter,
475â†’    width,
476â†’    height,
477â†’  });
478â†’}
