286â†’              <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
287â†’                <span className={modalStyles.modalCardTitle}>Browser Drafts</span>
288â†’                <span className={modalStyles.modalCardDesc} style={{ fontSize: '11px' }}>
289â†’                  Stored only in this browser on this machine.
290â†’                </span>
