294â†’                  No browser drafts found.
295â†’                </p>
296â†’              ) : (
297â†’                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
298â†’                  {savedProjects.map(p => (
299â†’                    <div key={p.id} className={modalStyles.modalCard} style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
300â†’                      <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
301â†’                        <span style={{ fontWeight: 500, fontSize: '13px' }}>{p.name}</span>
302â†’                        <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
303â†’                          {new Date(p.savedAt).toLocaleDateString()}
304â†’                        </span>
305â†’                      </div>
306â†’                      <div style={{ display: 'flex', gap: '8px' }}>
307â†’                        <button className={modalStyles.modalBtn} onClick={() => handleLoad(p.id)}>Load</button>
308â†’                        <button className={modalStyles.modalBtnDanger} onClick={() => handleDelete(p.id, p.name)}>Delete</button>
309â†’                      </div>
310â†’                    </div>
311â†’                  ))}
312â†’                </div>
313â†’              )}
314â†’            </div>
315â†’          </div>
316â†’          <button className={modalStyles.modalBtn} onClick={() => setShowLoadModal(false)} style={{ marginTop: '16px' }}>
317â†’            Cancel
318â†’          </button>
319â†’        </Modal>
320â†’      )}
321â†’    </EditorProvider>
322â†’  );
323â†’}
324â†’
325â†’export default function App() {
326â†’  return (
327â†’    <ProjectProvider>
328â†’      <ClipboardProvider>
329â†’        <AppInner />
330â†’      </ClipboardProvider>
331â†’    </ProjectProvider>
332â†’  );
333â†’}
