389â†’  });
390â†’
391â†’  if (!scene) return sheet;
392â†’
393â†’  const frameById = new Map(scene.viewports.map((viewport) => [viewport.id, viewport]));
394â†’
395â†’  return {
396â†’    ...sheet,
