420â†’export function fitViewportToSheet(viewport, sheet) {
421â†’  const paper = getPaperPreset(sheet.paperSize);
422â†’  const zones = buildSheetZones(paper);
423â†’  const captionClearance = getCaptionClearance(viewport);
424â†’  const captionAbove = viewport.captionPosition === 'above' ? captionClearance : 0;
425â†’  const captionBelow = viewport.captionPosition === 'below' ? captionClearance : 0;
426â†’  const width = clamp(
427â†’    viewport.width,
428â†’    SHEET_TOKENS.viewportMinWidth,
429â†’    zones.contentArea.width
430â†’  );
431â†’  const height = clamp(
432â†’    viewport.height,
433â†’    SHEET_TOKENS.viewportMinHeight,
434â†’    zones.contentArea.height - captionClearance
435â†’  );
436â†’  const maxX = zones.contentArea.x + zones.contentArea.width - width;
437â†’  const minY = zones.contentArea.y + captionAbove;
438â†’  const maxY = zones.contentArea.y + zones.contentArea.height - height - captionBelow;
439â†’
440â†’  return snapRectToGrid({
441â†’    ...viewport,
442â†’    width,
443â†’    height,
444â†’    x: clamp(viewport.x, zones.contentArea.x, maxX),
445â†’    y: clamp(viewport.y, minY, Math.max(minY, maxY)),
446â†’  });
447â†’}
